UPDATE `user`
SET current_outfit_key = #{outfitKey},
	current_gulbi_images_json = #{imagesJson}
WHERE id = #{userId}

UPDATE weekly_budget
SET reward_status = #{rewardStatus},
	reward_decided_at = NOW()
WHERE id = #{weeklyBudgetId}
  AND user_id = #{userId}
  AND reward_status = 'PENDING'
